    inputs: [{ name: "train_data", type: PortType.TABLE }],
    outputs: [
      { name: "model", type: PortType.MODEL },
      { name: "metrics", type: PortType.METRICS },
    ],
    params: [
      { name: "target_column", type: "text", default: "" },
      {
        name: "learning_rate",
        type: "slider",
        default: 0.01,
        min: 0.001,
        max: 1,
        step: 0.001,
      },
    ],
  },
  {
    type: "random_forest",
